import React from "react";
import './projects.css'

function Projects() {
    return (
      <div id="projects-body">
          <h3>Projects</h3>
          <ul  className="projects-list">
            <li id="project1"
                onClick={() => {
                  const project1Body = document.getElementById("project1-body");


                  if(project1Body.style.display === "" || project1Body.style.display === "none") {
                    project1Body.style = "display:block"
                  } else if(project1Body.style.display !== ""){
                    project1Body.style = "display:none"
                    }
                  }
                }
            > » Stranger's Things</li>
            <li id="project2"> » Fitness Tracker</li>
            <li id="project3"> » The Closet</li>
            <li id="project4"> » Guessing Game</li>
            <li id="project5"> » Across The Pond Soccer</li>
          </ul>
      </div>
    )
  }

export default Projects;
